    memoryAnchor: ["M = hele molecuulion; fragment = afgebroken stukje.", "Basispiek = hoogste staaf op 100%, niet per se M.", "M+1 is vaak één ¹³C; M+2 kan op Cl of Br wijzen."],
    miniCheck: [{ question: "Wat is gelijk bij twee isotopen van hetzelfde element?", answer: "Het aantal protonen." }, { question: "Wat doet GC vóór de MS?", answer: "Het scheidt stoffen uit een mengsel in de tijd." }, { question: "Is de basispiek altijd het hele molecuul?", answer: "Nee, het kan juist een stabiel fragmention zijn." }],
