    miniCheck: [{ question: "Welke kracht heeft zowel CH₄ als H₂O?", answer: "Vanderwaalskrachten." }, { question: "Waarom heeft methanol sterkere aantrekking dan dimethylether?", answer: "Methanol heeft een O—H-groep en kan waterstofbruggen doneren." }, { question: "Welke kant van water richt zich naar Na⁺?", answer: "De δ− O-kant, via ion-dipoolaantrekking." }],
